/* global console, process */
/*
 * decimation-cascade-bench.mjs — the VERIDICAL test of the recursion axis.
 *
 * Claim under test (recursion-tower): aeons emanate aeons by octave-fold descent,
 * carrier f_{n+1} = floor(f_n / 2). The sim survived a matched-band null at 3.82σ.
 * This drives it on REAL RF: TX a tone at f on the Pluto, receive on an RTL, find
 * the dominant carrier, DECIMATE-by-2, re-TX, repeat. Falsifiable prediction the
 * bench must survive: the MEASURED received carrier halves each round until it hits
 * the DC/noise floor in ~log2 rounds. REFUTATION: if the measured carriers do NOT
 * halve (spur dominates, channel re-injects broadband), the descent law is FALSE on
 * hardware and the recursion axis is decoration. Run with /opt/homebrew/bin/node.
 */
import { spawn } from 'node:child_process';
import { openSync, readFileSync, writeFileSync, existsSync } from 'node:fs';

const FS = 2_400_000;          // sample rate
const LO = 433_920_000;        // 433.92 MHz ISM
const N_TX = 131072;           // tone length (cyclic TX buffer)
const N_CAP = 2_400_000;       // 1s capture
const N_FFT = 131072;          // FFT window
const CAP_SKIP = 400_000;      // skip TX/AGC transient
const DC_GUARD_HZ = 12_000;    // exclude the LO/DC spur band when peak-finding
const F0 = 600_000;            // start carrier: 600 kHz offset
const SCALE = 8000;

const LIBIIO = process.env.GNOSIS_LIBIIO_BUILD || '/tmp/libiio_build/build';
const env = { ...process.env, DYLD_FALLBACK_FRAMEWORK_PATH: LIBIIO };
const IIO_ATTR = `${LIBIIO}/tests/iio_attr`;
const IIO_WRITEDEV = `${LIBIIO}/tests/iio_writedev`;
const IIO_INFO = `${LIBIIO}/tests/iio_info`;
const RTL_SDR = existsSync('/opt/homebrew/bin/rtl_sdr') ? '/opt/homebrew/bin/rtl_sdr' : 'rtl_sdr';
const ART = new URL('.', import.meta.url).pathname + '../.qa-artifacts/decimation';
import { mkdirSync } from 'node:fs';
mkdirSync(ART, { recursive: true });

function sh(cmd, args, opts = {}) {
  return new Promise((res) => {
    const c = spawn(cmd, args, { env, ...opts });
    let out = '', err = '';
    if (c.stdout) c.stdout.on('data', (d) => (out += d));
    if (c.stderr) c.stderr.on('data', (d) => (err += d));
    c.once('close', (code) => res({ code, out, err }));
  });
}

// in-place iterative radix-2 FFT
function fft(re, im) {
  const n = re.length;
  for (let i = 1, j = 0; i < n; i++) {
    let bit = n >> 1;
    for (; j & bit; bit >>= 1) j ^= bit;
    j ^= bit;
    if (i < j) { [re[i], re[j]] = [re[j], re[i]]; [im[i], im[j]] = [im[j], im[i]]; }
  }
  for (let len = 2; len <= n; len <<= 1) {
    const ang = (-2 * Math.PI) / len, wr = Math.cos(ang), wi = Math.sin(ang);
    for (let i = 0; i < n; i += len) {
      let cr = 1, ci = 0;
      for (let k = 0; k < len >> 1; k++) {
        const ar = re[i + k], ai = im[i + k];
        const br = re[i + k + (len >> 1)] * cr - im[i + k + (len >> 1)] * ci;
        const bi = re[i + k + (len >> 1)] * ci + im[i + k + (len >> 1)] * cr;
        re[i + k] = ar + br; im[i + k] = ai + bi;
        re[i + k + (len >> 1)] = ar - br; im[i + k + (len >> 1)] = ai - bi;
        const ncr = cr * wr - ci * wi; ci = cr * wi + ci * wr; cr = ncr;
      }
    }
  }
}

function synthTone(fHz) {
  const buf = Buffer.alloc(N_TX * 4); // int16 I,Q
  for (let n = 0; n < N_TX; n++) {
    const ph = (2 * Math.PI * fHz * n) / FS;
    buf.writeInt16LE(Math.max(-32767, Math.min(32767, Math.round(Math.cos(ph) * SCALE))), n * 4);
    buf.writeInt16LE(Math.max(-32767, Math.min(32767, Math.round(Math.sin(ph) * SCALE))), n * 4 + 2);
  }
  return buf;
}

// FFT a capture window; return dominant carrier Hz (signed) outside the DC guard, + peak/median ratio
function analyze(u8) {
  const re = new Float64Array(N_FFT), im = new Float64Array(N_FFT);
  for (let k = 0; k < N_FFT; k++) {
    re[k] = u8[(CAP_SKIP + k) * 2] - 127.5;
    im[k] = u8[(CAP_SKIP + k) * 2 + 1] - 127.5;
  }
  fft(re, im);
  const binHz = FS / N_FFT, guard = Math.round(DC_GUARD_HZ / binHz);
  let peak = -1, peakMag = 0;
  const mags = new Float64Array(N_FFT);
  for (let k = 0; k < N_FFT; k++) {
    const m = re[k] * re[k] + im[k] * im[k];
    mags[k] = m;
    const signedBin = k < N_FFT / 2 ? k : k - N_FFT; // -N/2..N/2
    if (Math.abs(signedBin) <= guard) continue; // skip DC/LO spur
    if (m > peakMag) { peakMag = m; peak = k; }
  }
  const signedPeak = peak < N_FFT / 2 ? peak : peak - N_FFT;
  const measuredHz = signedPeak * binHz;
  // crude SNR: peak vs median magnitude
  const sorted = Array.from(mags).sort((a, b) => a - b);
  const median = sorted[sorted.length >> 1] || 1e-9;
  return { measuredHz, snr: peakMag / median };
}

async function txCaptureMeasure(fHz, round) {
  const iq = `${ART}/tone-${round}.iq16`;
  const cap = `${ART}/cap-${round}.u8`;
  writeFileSync(iq, synthTone(fHz));
  // background cyclic TX (stdin = the tone file)
  const fd = openSync(iq, 'r');
  const tx = spawn(IIO_WRITEDEV, ['-u', PLUTO_URI, '-b', String(N_TX), '-c', 'cf-ad9361-dds-core-lpc', 'voltage0', 'voltage1'],
    { env, stdio: [fd, 'ignore', 'ignore'] });
  await new Promise((r) => setTimeout(() => r(), 300)); // let TX spin up
  await sh(RTL_SDR, ['-d', '0', '-f', String(LO), '-s', String(FS), '-g', '30', '-n', String(N_CAP), cap]);
  tx.kill('SIGKILL');
  const u8 = readFileSync(cap);
  return analyze(u8);
}

let PLUTO_URI = process.env.GNOSIS_PLUTO_URI || '';

async function main() {
  if (!PLUTO_URI) {
    const r = await sh(IIO_INFO, ['-s']);
    const m = (r.out + r.err).match(/usb:[0-9]+\.[0-9]+\.[0-9]+/);
    PLUTO_URI = m ? m[0] : '';
  }
  if (!PLUTO_URI) { console.error('no Pluto'); process.exit(1); }
  console.log(`=== octave-descent decimation cascade on the bench (Pluto ${PLUTO_URI}) ===`);
  // configure TX chain
  await sh(IIO_ATTR, ['-u', PLUTO_URI, '-c', 'ad9361-phy', 'altvoltage1', 'frequency', String(LO)]);
  await sh(IIO_ATTR, ['-u', PLUTO_URI, '-c', 'ad9361-phy', 'voltage0', 'sampling_frequency', String(FS)]);
  await sh(IIO_ATTR, ['-u', PLUTO_URI, '-c', 'ad9361-phy', 'voltage0', 'rf_bandwidth', String(FS)]);
  for (let i = 0; i < 3; i++) await sh(IIO_ATTR, ['-u', PLUTO_URI, '-c', 'ad9361-phy', 'voltage0', 'hardwaregain', '-10']);

  console.log('round  target Hz   measured Hz   ratio(prev)   floor(prev/2)   match   snr');
  let f = F0, prevMeasured = null, matches = 0, rounds = 0;
  while (f > DC_GUARD_HZ && rounds < 9) {
    const { measuredHz, snr } = await txCaptureMeasure(f, rounds);
    const ratio = prevMeasured ? (measuredHz / prevMeasured) : NaN;
    const predicted = prevMeasured ? Math.floor(prevMeasured / 2) : f;
    const match = prevMeasured ? Math.abs(measuredHz - predicted) < 0.08 * Math.abs(prevMeasured) : true;
    if (prevMeasured && match) matches++;
    console.log(
      `${String(rounds).padStart(3)}  ${String(f).padStart(9)}   ${measuredHz.toFixed(0).padStart(9)}` +
      `   ${prevMeasured ? ratio.toFixed(3) : '   -'}        ${prevMeasured ? String(predicted).padStart(7) : '   -'}` +
      `        ${prevMeasured ? (match ? 'YES' : 'no ') : ' - '}     ${snr.toFixed(0)}`
    );
    prevMeasured = measuredHz;
    f = Math.floor(Math.abs(measuredHz) / 2); // DECIMATE the RECEIVED carrier
    rounds++;
  }
  console.log(`\noctave-descent matches: ${matches}/${rounds - 1} rounds within 8%`);
  console.log(matches >= rounds - 2
    ? 'VERIDICAL ✓: the carrier halved per round through the real channel — descent survived hardware.'
    : 'REFUTED: the measured carriers did NOT track floor(f/2) — descent is sim decoration, recursion axis dies on RF.');
}

main();
